package com.example.Rest_Kafka_POC.controller;import com.example.Rest_Kafka_POC.pojo.Employee;import com.example.Rest_Kafka_POC.service.EmployeeService;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping("/employee")public class EmployeeController {    EmployeeService employeeService;    @GetMapping("/")    public String getWish() {        return "Hello";    }    @PostMapping("/create")    public ResponseEntity<String> postEmployeeRecord(@RequestBody Employee employee) {        ResponseEntity.status(HttpStatus.OK)                .body(employee.toString());        return null;    }    @GetMapping("/get")    public ResponseEntity<String> postEmployeeRecord(@RequestParam("id") int employeeId) {        System.out.println("The value is "+employeeId);        return null;    }}